1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
15	  const results = scenario.steps.map((step) => {
16	    const policyBase = step.items.reduce((sum, item) => {
17	      const base = item.type === "sword" ? 100 : item.type === "amulet" ? 60 : 0;
18	      return sum + base;
19	    }, 0);
20	    const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
21	    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
22	    return { premium };
23	  });
24	  return { results };
25	};
